// ============================================================
// GW-007 — API Gateway
// VERSION CORRIGÉE — CVF-001 + CVF-004 + CVF-006
// ============================================================
// ── CVF-001 : TOKEN DÉDIÉ GATEWAY ────────────────────────
const store = $getWorkflowStaticData('global');
const now   = Date.now();
const ts    = new Date().toISOString();
const raw   = $input.first().json;
const body  = raw.body || raw;

const SOC_TOKEN = String($vars.GATEWAY_TOKEN || '').trim();
if (!SOC_TOKEN) {
  return [{ json: { error: 'GATEWAY_MISCONFIGURATION',
    message: 'GATEWAY_TOKEN non configuré', timestamp: ts, gateway: true } }];
}

// ── TOKEN — lecture headers + body + raw ──────────────────
const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  raw['x-soc-token'] ||
  raw.soc_token      ||
  body['x-soc-token'] ||
  body.soc_token     || ''
).trim();

if (!receivedToken) {
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token manquant', gateway: true, timestamp: ts } }];
}
if (receivedToken !== SOC_TOKEN) {
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token invalide', gateway: true, timestamp: ts } }];
}
// ── CVF-006 : SLIDING WINDOW RATE-LIMITING ───────────────
const clientIP = String(
  body.ip || body.source_ip || raw.ip || 'unknown'
).split(',')[0].trim();
const safeIP = clientIP.replace(/[.:]/g, '_').substring(0, 50);
const rlKey  = 'GW_RL_' + safeIP;

let rl = { timestamps: [] };
try { rl = JSON.parse(store[rlKey] || '{}'); } catch(e) {}

const WINDOW_MS = 60000;
const MAX_REQS  = 100;
const cutoff    = now - WINDOW_MS;
rl.timestamps   = (rl.timestamps || []).filter(t => t > cutoff);

if (rl.timestamps.length >= MAX_REQS) {
  const retryAfter = Math.ceil((rl.timestamps[0] + WINDOW_MS - now) / 1000);
  return [{ json: {
    error      : 'RATE_LIMITED',
    message    : 'Limite: ' + MAX_REQS + ' req/min',
    retry_after: retryAfter + 's',
    gateway    : true, timestamp: ts
  }}];
}
rl.timestamps.push(now);
store[rlKey] = JSON.stringify(rl);

// ── CIRCUIT BREAKER ───────────────────────────────────────
const requestedRoute = String(
  body.route || body.target || raw.route || ''
).toLowerCase().trim();
const cbKey = 'GW_CB_' + requestedRoute;
let cb = {};
try { cb = JSON.parse(store[cbKey] || '{}'); } catch(e) {}

if (cb.open && (now - cb.opened_at) < 120000) {
  return [{ json: {
    error    : 'CIRCUIT_OPEN',
    message  : 'Route ' + requestedRoute + ' temporairement indisponible',
    retry_in : Math.ceil((120000 - (now - cb.opened_at)) / 1000) + 's',
    gateway  : true, timestamp: ts
  }}];
}

// ── CVF-004 : ROUTING DEPUIS $vars (plus de hardcoding) ──
const BASE = String($vars.WEBHOOK_BASE || '').trim();

// Le gateway forward le token du workflow CIBLE, pas le sien
const ROUTES = {
  'siem'    : { target: 'siem-logs',            token: $vars.SIEM_TOKEN    },
  'dispatch': { target: 'soar-dispatch',         token: $vars.ORCH_TOKEN     },
  'bf'      : { target: 'soar-trigger',          token: $vars.SOAR_BF_TOKEN  },
  'phishing': { target: 'soar-phishing-trigger', token: $vars.SOAR_PH_TOKEN  },
  'sim'     : { target: 'sim-simulator',         token: $vars.SIM_TOKEN      },
  'report'  : { target: 'report',               token: $vars.REPORT_TOKEN   }
};

if (!requestedRoute || !ROUTES[requestedRoute]) {
  return [{ json: {
    error       : 'INVALID_ROUTE',
    message     : 'Route inconnue: ' + requestedRoute,
    valid_routes: Object.keys(ROUTES),
    gateway     : true, timestamp: ts
  }}];
}

const route     = ROUTES[requestedRoute];
const requestId = 'GW-' + now + '-' +
  Math.random().toString(36).substr(2, 6).toUpperCase();

// ── AUDIT LOG ─────────────────────────────────────────────
const SENSITIVE_KEYS = [
  'soc_token','x-soc-token','token','authorization','password','secret'
];
const auditEntry = {
  gateway_ts   : ts,
  request_id   : requestId,
  route        : requestedRoute,
  target       : route.target,
  client_ip    : clientIP,
  payload_keys : Object.keys(body)
    .filter(k => !SENSITIVE_KEYS.includes(k.toLowerCase()))
    .join(',').substring(0, 200)
};
const auditLog = store['GW_AUDIT_LOG']
  ? JSON.parse(store['GW_AUDIT_LOG']) : [];
auditLog.push(auditEntry);
if (auditLog.length > 500) auditLog.splice(0, auditLog.length - 500);
store['GW_AUDIT_LOG'] = JSON.stringify(auditLog);

// ── PAYLOAD PROPRE + INJECTION TOKEN CIBLE ───────────────
const cleanBody = {};
Object.keys(body).forEach(k => {
  if (!SENSITIVE_KEYS.includes(k.toLowerCase())) {
    cleanBody[k] = body[k];
  }
});

console.log('[GW-007] ROUTED: ' + requestedRoute +
  ' → ' + route.target +
  ' — IP: ' + clientIP + ' — ReqID: ' + requestId);

return [{ json: {
  ...cleanBody,
  'x-soc-token'  : String(route.token || ''),
  _gateway       : true,
  _gateway_ts    : ts,
  _gateway_route : requestedRoute,
  _gateway_target: route.target,
  _gateway_client: clientIP,
  _request_id    : requestId,
  target_url     : BASE + '/' + route.target
}}];

// ============================================================
// GW-007 — Code_CircuitBreakerFeedback — VERSION FINALE
// Distingue erreurs backend réelles vs erreurs auth légitimes
// ============================================================

const store = $getWorkflowStaticData('global');
const input = $input.first().json;
const now   = Date.now();
const ts    = new Date().toISOString();

const route  = input._gateway_route || 'unknown';
const cbKey  = 'GW_CB_' + route;
const errKey = 'GW_ERR_' + route;

// Ne pas compter comme erreur circuit les erreurs d'authentification
// (UNAUTHORIZED, RATE_LIMITED) — ce sont des réponses applicatives valides
const AUTH_ERRORS = ['UNAUTHORIZED', 'RATE_LIMITED', 'INVALID_ROUTE', 'CIRCUIT_OPEN'];
const errorCode   = String(input.error || '');
const isAuthError = AUTH_ERRORS.includes(errorCode);

// Erreur réelle = erreur HTTP 5xx ou ERROR sans code d'auth connu
const isRealError = (
  !isAuthError &&
  (
    input.status === 'ERROR' ||
    (input.statusCode && input.statusCode >= 500) ||
    (input.error && !isAuthError)
  )
);

let cb  = {};
let err = { timestamps: [] };
try { cb  = JSON.parse(store[cbKey]  || '{}'); } catch(e) {}
try { err = JSON.parse(store[errKey] || '{}'); } catch(e) {}

if (isRealError) {
  err.timestamps = (err.timestamps || []).filter(t => t > now - 120000);
  err.timestamps.push(now);
  store[errKey] = JSON.stringify(err);

  const ERROR_THRESHOLD = 5;
  if (err.timestamps.length >= ERROR_THRESHOLD) {
    cb = { open: true, opened_at: now, route, error_count: err.timestamps.length };
    store[cbKey] = JSON.stringify(cb);
    console.log('[GW-007][CB] Circuit OUVERT — route: ' + route +
      ' — ' + err.timestamps.length + ' erreurs réelles en 2min');
  } else {
    console.log('[GW-007][CB] Erreur réelle ' + err.timestamps.length +
      '/5 — route: ' + route + ' — code: ' + errorCode);
  }
} else {
  if (err.timestamps && err.timestamps.length > 0) {
    store[errKey] = JSON.stringify({ timestamps: [] });
  }
  if (cb.open) {
    cb = { open: false, closed_at: now };
    store[cbKey] = JSON.stringify(cb);
    console.log('[GW-007][CB] Circuit FERMÉ — route: ' + route);
  }
}

return [{ json: {
  ...input,
  _cb_checked   : true,
  _is_real_error: isRealError,
  _is_auth_error: isAuthError
}}];
